"1.R.1":[{q:"Which word rhymes with 'cat'?",correct:"Hat",options:["Dog","Hat","Cup","Red"],sol:"1.R.1",skill:"Rhyming"},{q:"What sound does the letter 'B' make?",correct:"/b/ as in 'ball'",options:["/d/ as in 'dog'","/b/ as in 'ball'","/p/ as in 'pig'","/m/ as in 'moon'"],sol:"1.R.1",skill:"Letter sounds"},{q:"How many syllables in 'butterfly'?",correct:"3",options:["1","2","3","4"],sol:"1.R.1",skill:"Syllables"},{q:"What word do you get when you blend /s/ /u/ /n/?",correct:"Sun",options:["Fun","Run","Sun","Bun"],sol:"1.R.1",skill:"Blending"},{q:"Which word begins with the same sound as 'fish'?",correct:"Fun",options:["Sun","Fun","Run","Bun"],sol:"1.R.1",skill:"Beginning sounds"},{q:"What is the vowel sound in 'bed'?",correct:"Short e",options:["Short a","Short e","Short i","Short o"],sol:"1.R.1",skill:"Short vowels"},{q:"Which is a sight word that can't easily be sounded out?",correct:"The",options:["Cat","Dog","The","Sit"],sol:"1.R.1",skill:"Sight words"},{q:"What happens when you add 'ing' to 'jump'?",correct:"Jumping",options:["Jumped","Jumps","Jumping","Jumper"],sol:"1.R.1",skill:"Word endings"}],
"1.R.2":[{q:"What is the main idea of a story?",correct:"What the story is mostly about",options:["The first sentence","What the story is mostly about","The title","The last word"],sol:"1.R.2",skill:"Main idea"},{q:"Who are the characters in a story?",correct:"The people or animals the story is about",options:["The author","The people or animals the story is about","The readers","The illustrator"],sol:"1.R.2",skill:"Characters"},{q:"What is the setting of a story?",correct:"Where and when the story takes place",options:["The main character","Where and when the story takes place","The ending","The problem"],sol:"1.R.2",skill:"Setting"},{q:"What happens at the beginning, middle, and end of a story?",correct:"The events in order",options:["Just the ending","Just the beginning","The events in order","Only the problem"],sol:"1.R.2",skill:"Sequence"},{q:"What is a prediction?",correct:"A guess about what will happen next in a story",options:["The ending","A guess about what will happen next in a story","The title","A fact"],sol:"1.R.2",skill:"Predict"},{q:"What does an illustrator do?",correct:"Draws the pictures in a book",options:["Writes the words","Draws the pictures in a book","Reads the book","Sells the book"],sol:"1.R.2",skill:"Book concepts"},{q:"Why do we read with expression?",correct:"To make the story interesting and show feelings",options:["To read faster","To make the story interesting and show feelings","To be louder","To skip words"],sol:"1.R.2",skill:"Fluency"},{q:"How can pictures help you understand a story?",correct:"They show what is happening and give clues about the text",options:["They are just decoration","They show what is happening and give clues about the text","They replace the words","They are not helpful"],sol:"1.R.2",skill:"Use illustrations"}],
"1.W.1":[{q:"Every sentence begins with a ___",correct:"Capital letter",options:["Period","Small letter","Capital letter","Number"],sol:"1.W.1",skill:"Capitalization"},{q:"What goes at the end of a telling sentence?",correct:"A period (.)",options:["A question mark","An exclamation mark","A period (.)","A comma"],sol:"1.W.1",skill:"Punctuation"},{q:"What goes at the end of a question?",correct:"A question mark (?)",options:["A period","A question mark (?)","An exclamation mark","Nothing"],sol:"1.W.1",skill:"Punctuation"},{q:"Which is a complete sentence?",correct:"The dog runs fast.",options:["Runs fast","Dog the","The dog runs fast.","Fast dog"],sol:"1.W.1",skill:"Sentences"},{q:"What is a noun?",correct:"A word that names a person, place, or thing",options:["An action word","A word that names a person, place, or thing","A describing word","A small word"],sol:"1.W.1",skill:"Nouns"},{q:"What is a verb?",correct:"An action word that tells what someone does",options:["A naming word","A describing word","An action word that tells what someone does","A connecting word"],sol:"1.W.1",skill:"Verbs"},{q:"Why do we use spaces between words when writing?",correct:"So the reader can tell where each word starts and ends",options:["To waste paper","So the reader can tell where each word starts and ends","It doesn't matter","For decoration"],sol:"1.W.1",skill:"Spacing"},{q:"What should you do before writing a story?",correct:"Think about what you want to say and plan your ideas",options:["Just start writing randomly","Think about what you want to say and plan your ideas","Copy someone else","Write the ending first"],sol:"1.W.1",skill:"Planning"}],
