"5.R.1":[{q:"What does the Latin root 'aud' mean?",correct:"To hear",options:["To see","To hear","To write","To run"],sol:"5.R.1",skill:"Latin roots"},{q:"What is an analogy?",correct:"A comparison showing how two pairs of words are related in the same way",options:["A synonym","A comparison showing how two pairs of words are related in the same way","A definition","An antonym"],sol:"5.R.1",skill:"Analogies"},{q:"Complete: Hot is to cold as big is to ___",correct:"Small",options:["Large","Small","Huge","Warm"],sol:"5.R.1",skill:"Analogies"},{q:"What does the prefix 'mis-' mean?",correct:"Wrong or badly (as in 'misunderstand')",options:["Again","Not","Wrong or badly (as in 'misunderstand')","Before"],sol:"5.R.1",skill:"Prefixes"},{q:"What is a thesaurus used for?",correct:"Finding synonyms and antonyms for words",options:["Finding definitions","Finding synonyms and antonyms for words","Finding facts","Checking spelling"],sol:"5.R.1",skill:"Reference skills"},{q:"What does the Greek root 'graph' mean?",correct:"To write or draw",options:["To read","To speak","To write or draw","To count"],sol:"5.R.1",skill:"Greek roots"},{q:"What is denotation?",correct:"The dictionary definition of a word",options:["The feeling of a word","The dictionary definition of a word","A synonym","An antonym"],sol:"5.R.1",skill:"Denotation"},{q:"What strategy helps with unfamiliar words?",correct:"Breaking the word into prefix, root, and suffix parts",options:["Skipping it","Breaking the word into prefix, root, and suffix parts","Guessing randomly","Asking every time"],sol:"5.R.1",skill:"Word analysis"}],
"5.R.2":[{q:"What is the climax of a story?",correct:"The most exciting or turning point of the story",options:["The beginning","The most exciting or turning point of the story","The ending","The setting"],sol:"5.R.2",skill:"Plot structure"},{q:"What is a conflict in a story?",correct:"The struggle or problem that drives the plot",options:["A character","The struggle or problem that drives the plot","The setting","A description"],sol:"5.R.2",skill:"Conflict"},{q:"What is the author's tone?",correct:"The author's attitude toward the subject (serious, humorous, sad)",options:["How loud to read","The author's attitude toward the subject (serious, humorous, sad)","The topic","The genre"],sol:"5.R.2",skill:"Tone"},{q:"What does it mean to compare texts?",correct:"To look at how two or more texts are similar and different",options:["To copy texts","To look at how two or more texts are similar and different","To read texts aloud","To write new texts"],sol:"5.R.2",skill:"Compare texts"},{q:"What is a reliable source for research?",correct:"Published by experts, supported by evidence, up-to-date",options:["Any website","A social media post","Published by experts, supported by evidence, up-to-date","A random blog"],sol:"5.R.2",skill:"Evaluate sources"},{q:"What does 'synthesize' mean in reading?",correct:"To combine information from multiple sources to form new understanding",options:["To summarize one text","To combine information from multiple sources to form new understanding","To memorize facts","To copy text"],sol:"5.R.2",skill:"Synthesize"},{q:"What is dramatic irony?",correct:"When the reader knows something the characters do not",options:["A funny moment","When the reader knows something the characters do not","A sad ending","A plot twist"],sol:"5.R.2",skill:"Literary devices"},{q:"What is the resolution of a story?",correct:"The part where the conflict is resolved and the story wraps up",options:["The beginning","The conflict","The climax","The part where the conflict is resolved and the story wraps up"],sol:"5.R.2",skill:"Plot structure"}],
"5.W.1":[{q:"What is a research report?",correct:"A paper that presents information gathered from multiple sources",options:["A story","A poem","A research report","A letter"],sol:"5.W.1",skill:"Research writing"},{q:"What is plagiarism?",correct:"Using someone else's words or ideas without giving credit",options:["Good writing","Using someone else's words or ideas without giving credit","A writing style","A type of essay"],sol:"5.W.1",skill:"Academic integrity"},{q:"How should you organize a research paper?",correct:"Introduction, body paragraphs with evidence, and conclusion",options:["Random order","Introduction, body paragraphs with evidence, and conclusion","Longest to shortest","Only one paragraph"],sol:"5.W.1",skill:"Organization"},{q:"What is a credible source?",correct:"A source that is trustworthy, accurate, and written by qualified authors",options:["Any source","A source that is trustworthy, accurate, and written by qualified authors","Only books","Only websites"],sol:"5.W.1",skill:"Source evaluation"},{q:"What is paraphrasing?",correct:"Restating information in your own words while keeping the meaning",options:["Copying exactly","Restating information in your own words while keeping the meaning","Shortening text","Deleting text"],sol:"5.W.1",skill:"Paraphrasing"},{q:"What makes a strong conclusion?",correct:"Restates the main idea, summarizes key points, leaves a final thought",options:["Introduces new topics","Restates the main idea, summarizes key points, leaves a final thought","Just says 'The End'","Repeats the introduction"],sol:"5.W.1",skill:"Conclusions"},{q:"What is a counterargument?",correct:"An opposing viewpoint that you address to strengthen your argument",options:["An agreement","An opposing viewpoint that you address to strengthen your argument","A question","A conclusion"],sol:"5.W.1",skill:"Argumentative writing"},{q:"Why should writing have varied sentence structure?",correct:"To make writing more interesting and improve flow",options:["It shouldn't","To make writing more interesting and improve flow","To confuse readers","To use more words"],sol:"5.W.1",skill:"Sentence variety"}],
